    if (pauseDoc) {
      this.wireBtn(pauseDoc, 'btn-resume', () => this.gameRef?.handleUIAction('resume'));
      this.wireBtn(pauseDoc, 'btn-quit', () => this.gameRef?.handleUIAction('quit'));
    } else allWired = false;

